namespace sv_0713e900213c422baac7b0963da6f645.Services;

/// <summary>
/// Stateless service that simulates checking inventory levels.
/// Registered as singleton since it holds no per-user state.
/// </summary>
public sealed class InventoryAlertService
{
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate a database query with a random result 0–15.
        var count = Random.Shared.Next(0, 16);
        return Task.FromResult(count);
    }
}

namespace sv_0713e900213c422baac7b0963da6f645.Services;

/// <summary>
/// Per-circuit (scoped) state that tracks the selected warehouse and latest
/// low-stock alert count. Components subscribe to <see cref="OnChange"/> to
/// be notified when any value changes, enabling cross-component
/// synchronization without parent-child relationships.
/// </summary>
public sealed class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new("WH-A", "Warehouse A"),
        new("WH-B", "Warehouse B"),
        new("WH-C", "Warehouse C"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;
    private int _lowStockCount;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == _currentWarehouseId).Name;

    public int LowStockCount => _lowStockCount;

    /// <summary>
    /// Fired whenever the selected warehouse or alert count changes.
    /// Subscribers must call <see cref="Microsoft.AspNetCore.Components.ComponentBase.InvokeAsync(System.Action)"/>
    /// + <c>StateHasChanged</c> on the UI thread.
    /// </summary>
    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        // Reset count when warehouse changes; next poll will refresh it.
        _lowStockCount = 0;
        NotifyStateChanged();
    }

    public void SetLowStockCount(int count)
    {
        _lowStockCount = count;
        NotifyStateChanged();
    }

    private void NotifyStateChanged() => OnChange?.Invoke();
}

