toolArgs.new_str:
@page "/"
@using sv_0713e900213c422baac7b0963da6f645.Services
@rendermode InteractiveServer
@inject WarehouseState State
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>@State.CurrentWarehouseName — Dashboard</h1>

<div class="card mt-3" style="max-width: 24rem;">
    <div class="card-body">
        <h5 class="card-title">Low-Stock Alerts</h5>
        <p class="display-4">
            @if (_loading)
            {
                <span class="spinner-border spinner-border-sm"></span>
            }
            else
            {
                @State.LowStockCount
            }
        </p>
        <p class="text-muted mb-0">
            Items below minimum level &bull; refreshes every 10 s
        </p>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private bool _loading = true;

    protected override void OnInitialized()
    {
        State.OnChange += HandleStateChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollAsync(_cts.Token);
            // Trigger the first poll immediately via PollAsync;
            // no extra call needed here.
        }
    }

    private async Task PollAsync(CancellationToken ct)
    {
        try
        {
            while (!ct.IsCancellationRequested)
            {
                var count = await AlertService.GetLowStockCountAsync(State.CurrentWarehouseId);
                _loading = false;
                // Updating state notifies ALL subscribers (sidebar badge, etc.)
                State.SetLowStockCount(count);
                await Task.Delay(TimeSpan.FromSeconds(10), ct);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose / navigation away.
        }
    }

    private async void HandleStateChanged()
    {
        await InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        State.OnChange -= HandleStateChanged;
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

